import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams } from 'react-router-dom';
import Navbar from '../components/Navbar';

const API = '';

export default function Project() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [projects, setProjects] = useState([]);
  const [kategoriList, setKategoriList] = useState([]);
  const filterKategori = parseInt(searchParams.get('kategori')) || 0;
  const cardRefs = useRef([]);

  useEffect(() => {
    const url = filterKategori > 0
      ? `${API}/api/projects/public?kategori=${filterKategori}`
      : `${API}/api/projects/public`;
    fetch(url).then(r => r.json()).then(setProjects).catch(console.error);
  }, [filterKategori]);

  useEffect(() => {
    fetch(`${API}/api/kategori`).then(r => r.json()).then(setKategoriList).catch(console.error);
  }, []);

  useEffect(() => {
    cardRefs.current.forEach((el) => {
      if (el) {
        el.style.opacity = '0';
        el.style.transform = 'translateY(30px)';
        el.style.transition = 'all 0.7s cubic-bezier(0.34,1.56,0.64,1)';
      }
    });
    const timer = setTimeout(() => {
      cardRefs.current.forEach((el, i) => {
        if (el) {
          setTimeout(() => {
            el.style.opacity = '1';
            el.style.transform = 'translateY(0)';
          }, i * 80);
        }
      });
    }, 50);
    return () => clearTimeout(timer);
  }, [projects]);

  return (
    <>
      <style>{`
        :root {
          --gradient-main:linear-gradient(135deg,#ff6b9d 0%,#ff4d7a 40%,#ff2d5a 80%,#ff6b9d 100%);
          --text-dark:#1a1a2e;--text-gray:#6b7280;
          --glass-bg:rgba(255,255,255,0.78);--glass-border:rgba(255,255,255,0.5);
          --glass-shadow:0 8px 32px rgba(255,75,122,0.12);
          --radius-lg:28px;--radius-md:18px;
          --transition:all 0.5s cubic-bezier(0.34,1.56,0.64,1);
          --choco-900:#24140f;--cream-50:#fff8ed;--caramel:#c98545;
        }
        body{background:linear-gradient(160deg,#fff5f7 0%,#ffe8ee 30%,#ffdce4 60%,#fff0f3 100%);color:var(--text-dark);min-height:100vh}
        @keyframes floatOrb{0%,100%{transform:translate(0,0)scale(1)}25%{transform:translate(40px,-50px)scale(1.15)}50%{transform:translate(-25px,25px)scale(0.85)}75%{transform:translate(50px,35px)scale(1.1)}}
        @keyframes gradientMove{0%,100%{background-position:0% 50%}50%{background-position:100% 50%}}
        @keyframes shimmer{0%,100%{background-position:0% 50%}50%{background-position:100% 50%}}
        @keyframes slideDown{from{transform:translateX(-50%) translateY(-120px);opacity:0}to{transform:translateX(-50%) translateY(0);opacity:1}}

        .bg-orb{position:absolute;border-radius:50%;filter:blur(100px);animation:floatOrb 25s ease-in-out infinite}
        .bg-orb:nth-child(1){width:500px;height:500px;background:#ff6b9d;top:-200px;right:-150px;opacity:0.15}
        .bg-orb:nth-child(2){width:400px;height:400px;background:#ff8aae;bottom:-150px;left:-120px;animation-delay:-8s;opacity:0.2}
        .bg-orb:nth-child(3){width:350px;height:350px;background:#ffb3c8;top:40%;left:30%;animation-delay:-16s;opacity:0.15}

        /* Sakura petals */
        @keyframes sakuraFall{0%{transform:translateY(-20px) rotate(0deg);opacity:0}10%{opacity:var(--opacity)}90%{opacity:var(--opacity)}100%{transform:translateY(100vh) rotate(720deg) translateX(calc(sin(var(--left)) * 80px));opacity:0}}
        .sakura-petal{
          position:absolute;left:var(--left);top:-30px;
          width:var(--size);height:var(--size);
          background:radial-gradient(ellipse at 30% 30%,#ffb3c8,#ff6b9d);
          border-radius:50% 0 50% 0;
          animation:sakuraFall var(--duration) linear var(--delay) infinite;
          opacity:0;
        }

        .main-content{position:relative;z-index:1;padding-top:100px}
        .page-header-glass{
          background:linear-gradient(145deg,rgba(50,28,20,0.94),rgba(36,20,15,0.90));
          border:1px solid rgba(255,248,237,0.16);
          box-shadow:0 24px 80px rgba(36,20,15,0.18),inset 0 1px 0 rgba(255,248,237,0.12);
          border-radius:var(--radius-lg);padding:2.5rem 3rem;margin-bottom:2rem;
          position:relative;overflow:hidden;color:#fff8ed;
        }
        .page-title{font-size:2.5rem;font-weight:900;margin-bottom:0.5rem;letter-spacing:-0.5px;color:#fff8ed}
        .page-title .gradient-text{
          background:linear-gradient(120deg,#fff8ed 0%,#f1c28a 35%,#fff2d8 55%,#c98545 78%,#fff8ed 100%);
          -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;
          background-size:260% 260%;animation:gradientMove 4s ease-in-out infinite;
        }
        .page-title i{color:#f1c28a}
        .page-subtitle{color:rgba(255,248,237,0.72);font-size:1rem}

        .filter-section{margin-bottom:2rem;display:flex;flex-wrap:wrap;justify-content:center;gap:0.5rem}
        .filter-btn{
          padding:0.5rem 1.4rem;border-radius:50px;border:1px solid rgba(255,75,122,0.15);
          background:var(--glass-bg);color:var(--text-gray);
          text-decoration:none;font-size:0.88rem;font-weight:500;
          transition:var(--transition);cursor:pointer;
        }
        .filter-btn:hover,.filter-btn.active{
          background:var(--gradient-main);color:white;
          border-color:transparent;transform:translateY(-2px);
          box-shadow:0 4px 16px rgba(255,75,122,0.25);
        }

        .project-card{
          background:var(--glass-bg);backdrop-filter:blur(20px);
          border-radius:var(--radius-md);border:1px solid rgba(255,107,157,0.1);
          box-shadow:0 4px 16px rgba(255,75,122,0.08);
          overflow:hidden;transition:var(--transition);height:100%;
        }
        .project-card:hover{transform:translateY(-8px);box-shadow:0 16px 48px rgba(255,75,122,0.18);border-color:rgba(255,107,157,0.2)}
        .project-card-img{width:100%;height:200px;object-fit:cover;display:block}
        .project-card-body{padding:1.5rem}
        .project-card-title{font-size:1.05rem;font-weight:700;color:var(--text-dark);margin-bottom:0.3rem;display:block}
        .project-card-kategori{font-size:0.8rem;color:#ff4d7a;font-weight:600;display:block;margin-bottom:0.5rem}
        .project-card-desc{font-size:0.88rem;color:var(--text-gray);margin-bottom:1rem;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;overflow:hidden}
        .project-tech{display:flex;flex-wrap:wrap;gap:0.35rem;margin-bottom:1rem}
        .project-tech-badge{background:rgba(255,75,122,0.08);color:#ff4d7a;padding:0.25rem 0.75rem;border-radius:50px;font-size:0.75rem;font-weight:600;border:1px solid rgba(255,75,122,0.1)}
        .project-card-links{display:flex;gap:0.75rem}
        .project-card-links a{
          display:inline-flex;align-items:center;gap:0.4rem;font-size:0.82rem;font-weight:600;
          color:var(--text-gray);text-decoration:none;padding:0.4rem 1rem;
          border-radius:50px;border:1px solid rgba(0,0,0,0.08);transition:var(--transition);
        }
        .project-card-links a:hover{background:var(--gradient-main);color:white;border-color:transparent;transform:translateY(-2px)}

        .glass-card{
          background:var(--glass-bg);backdrop-filter:blur(20px);
          border-radius:var(--radius-md);border:1px solid var(--glass-border);
          box-shadow:var(--glass-shadow);padding:2rem;
        }
        .footer-glass{background:var(--glass-bg);backdrop-filter:blur(20px);border-top:1px solid rgba(255,107,157,0.1);padding:1.5rem 0;margin-top:4rem}
        .footer-text{font-size:0.9rem;color:var(--text-gray)}
        @keyframes pulseBadge{0%,100%{transform:scale(1)}50%{transform:scale(1.05)}}
        .heart{color:#ff4d7a;animation:pulseBadge 1.5s ease-in-out infinite;display:inline-block}
        .code-icon{color:#ff4d7a}
      `}</style>

      {/* Background */}
      <div style={{ position: 'fixed', inset: 0, zIndex: 0, overflow: 'hidden', pointerEvents: 'none' }}>
        <div className="bg-orb"></div>
        <div className="bg-orb"></div>
        <div className="bg-orb"></div>
        {[
          { left: '7%', size: '14px', opacity: '0.44', duration: '19s', delay: '-2s' },
          { left: '30%', size: '18px', opacity: '0.56', duration: '23s', delay: '-9s' },
          { left: '52%', size: '12px', opacity: '0.38', duration: '17s', delay: '-5s' },
          { left: '70%', size: '20px', opacity: '0.50', duration: '25s', delay: '-13s' },
          { left: '91%', size: '15px', opacity: '0.42', duration: '21s', delay: '-7s' },
        ].map((p, i) => (
          <span key={i} className="sakura-petal" style={{ '--left': p.left, '--size': p.size, '--opacity': p.opacity, '--duration': p.duration, '--delay': p.delay }}></span>
        ))}
      </div>

      <Navbar />

      <div className="main-content">
        <div className="container">
          {/* Header */}
          <div className="page-header-glass">
            <h1 className="page-title">
              <i className="fas fa-folder-open me-2"></i>
              <span className="gradient-text">Project Portfolio</span>
            </h1>
            <p className="page-subtitle">Kumpulan project yang telah saya kerjakan</p>
          </div>

          {/* Filter */}
          <div className="filter-section">
            <button
              className={`filter-btn ${filterKategori === 0 ? 'active' : ''}`}
              onClick={() => setSearchParams({})}
            >
              <i className="fas fa-th me-1"></i>Semua
            </button>
            {kategoriList.map((k) => (
              <button
                key={k.id}
                className={`filter-btn ${filterKategori === k.id ? 'active' : ''}`}
                onClick={() => setSearchParams({ kategori: k.id })}
              >
                {k.kategori}
              </button>
            ))}
          </div>

          {/* Project Grid */}
          {projects.length > 0 ? (
            <div className="row g-4">
              {projects.map((project, i) => {
                const teknologiList = project.teknologi ? project.teknologi.split('|') : [];
                return (
                  <div className="col-md-6 col-lg-4" key={project.id}>
                    <div className="project-card" ref={(el) => { cardRefs.current[i] = el; }}>
                      {project.gambar ? (
                        <img src={`/uploads/${project.gambar}`} alt={project.nama_project} className="project-card-img" />
                      ) : (
                        <div className="project-card-img d-flex align-items-center justify-content-center"
                          style={{ background: 'linear-gradient(135deg,#f5e5cd 0%,#fff8ed 100%)' }}>
                          <i className="fas fa-image" style={{ fontSize: '3rem', color: '#8a4b2a' }}></i>
                        </div>
                      )}
                      <div className="project-card-body">
                        <span className="project-card-title">{project.nama_project}</span>
                        <span className="project-card-kategori">{project.kategori}</span>
                        <p className="project-card-desc">{project.deskripsi}</p>
                        <div className="project-tech">
                          {teknologiList.map((t, j) => (
                            <span className="project-tech-badge" key={j}>{t}</span>
                          ))}
                        </div>
                        <div className="project-card-links">
                          {project.github && (
                            <a href={project.github} target="_blank" rel="noreferrer">
                              <i className="fab fa-github me-1"></i><span>GitHub</span>
                            </a>
                          )}
                          {project.demo && (
                            <a href={project.demo} target="_blank" rel="noreferrer">
                              <i className="fas fa-external-link-alt me-1"></i><span>Demo</span>
                            </a>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="glass-card text-center py-5">
              <i className="fas fa-inbox" style={{ fontSize: '4rem', color: '#8a4b2a' }}></i>
              <h5 className="mt-3 text-muted">Belum ada project</h5>
            </div>
          )}
        </div>
      </div>

      <footer className="footer-glass">
        <div className="container">
          <div className="text-center footer-text">
            <span className="code-icon"><i className="fas fa-code me-1"></i></span> Dibuat dengan{' '}
            <span className="heart"><i className="fas fa-heart"></i></span>{' '}
            oleh Hagia Sofiana &bull; {new Date().getFullYear()}
          </div>
        </div>
      </footer>
    </>
  );
}
